3	/** Maps mistaken / legacy persisted colIds to the grid `colId`. */
4	function normalizeRfqColId(colId: string): string {
5	  if (colId === 'Factory_updated') {
6	    return 'factory_updated';
7	  }
8	  return colId;
9	}
