11	/** * RFQ grid column **order** is defined by `RFQ_COLUMN_HEADERS_CONFIG` → `colHeaders` array order
12	 * in `rfq.grid.config.ts` (after role filtering in the component). This function builds the
13	 * `ColumnState[]` passed to `applyColumnState({ applyOrder: true })` so the UI column order
14	 * always matches that list.
15	 *
16	 * Per-column settings from persistence (`getColumnState` / saved views / session), such as
17	 * `hide`, `width`, `pinned`, and `sort`, are preserved when a `colId` exists in both the
18	 * config headers and the saved state. Any `order` field is stripped so array order wins.
19	 */
20	export function buildRfqColumnStateInConfigOrder(
21	  colHeaders: any[] | null | undefined,
22	  savedColumnState: ColumnState[] | null | undefined
23	): ColumnState[] {
24	  if (!Array.isArray(colHeaders) || colHeaders.length === 0) {
25	    return Array.isArray(savedColumnState) ? [...savedColumnState] : [];
26	  }
27	
28	  const savedMap = new Map<string, ColumnState>();
29	  for (const s of savedColumnState ?? []) {
30	    if (!s?.colId) {
31	      continue;
32	    }
33	    const id = normalizeRfqColId(String(s.colId));
34	    if (!savedMap.has(id)) {
35	      savedMap.set(id, { ...s, colId: id });
36	    }
37	  }
38	
39	  const result: ColumnState[] = [];
40	  for (const col of colHeaders) {
41	    if (!col || typeof col !== 'object') {
42	      continue;
43	    }
44	    const colId = normalizeRfqColId(String(col.colId || col.field));
45	    if (!colId) {
46	      continue;
47	    }
48	
49	    const saved = savedMap.get(colId);
50	    if (saved) {
51	      const { order: _order, ...rest } = saved as ColumnState & { order?: number };
52	      result.push(rest as ColumnState);
53	    } else {
54	      result.push({ colId, hide: !!col.hide });
55	    }
56	  }
57	  return result;
58	}
