18	  sort?: 'asc' | 'desc' | null;
19	  sortIndex?: number | null;
20	}): Record<string, unknown> {
21	  const s: Record<string, unknown> = { colId: row.colId };
22	  if (row.hide !== undefined) s.hide = row.hide;
23	  if (row.pinned !== undefined && row.pinned !== null) s.pinned = row.pinned;
